package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  @Test
  void tryMakeAccessible_success() throws NoSuchMethodException {
    Constructor<String> constructor = String.class.getDeclaredConstructor(byte[].class);
    String result = ReflectionHelper.tryMakeAccessible(constructor);
    assertNull(result, "Expected null when accessibility change succeeds");
    assertTrue(constructor.canAccess(null), "Constructor should be accessible");
  }

  @Test
  void tryMakeAccessible_failure() throws Exception {
    // Create a spy of a Constructor to throw exception on setAccessible
    Constructor<?> constructor = mock(Constructor.class);
    when(constructor.toString()).thenReturn("mockConstructor");
    doThrow(new SecurityException("access denied")).when(constructor).setAccessible(true);

    // Also mock constructorToString static method via reflection hack
    // Since constructorToString is static and public, we can call it normally
    // But here we want to test the catch block, so we simulate the exception thrown by setAccessible
    String result = ReflectionHelper.tryMakeAccessible(constructor);
    assertNotNull(result);
    assertTrue(result.contains("Failed making constructor 'mockConstructor' accessible;"));
    assertTrue(result.contains("access denied"));
  }
}
